{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"],
    "decisions": [
      {
        "type": "confirmed_decision",
        "content": "공개 릴리스 목표는 smoke test가 통과될 경우 Friday 15:00 KST로 한다."
      },
      {
        "type": "confirmed_decision",
        "content": "packageName mismatch가 발생하면 먼저 package config를 확인한다. contract 자체가 잘못된 경우에만 script 검토로 넘어간다."
      }
    ],
    "non_decisions": {
      "rejected_proposals": [
        {
          "proposal": "smoke-theme-pack.mjs가 packageName mismatch를 무시하도록 변경한다.",
          "result": "rejected"
        }
      ],
      "internal_stretch_goals": [
        {
          "content": "Wednesday 릴리스는 확정 일정이 아니라 내부 stretch goal이다."
        }
      ],
      "unassigned_or_unconfirmed_items": [
        {
          "content": "README install steps는 Thursday까지 검토되면 좋다는 의견이 있었으나 owner가 지정되지 않았다."
        },
        {
          "content": "Hara가 generated tarball path를 확인할 예정이나 정확한 deadline은 정해지지 않았다."
        }
      ]
    },
    "risks": [
      {
        "content": "잘못된 tarball path는 릴리스를 지연시킬 수 있다."
      },
      {
        "content": "README install steps가 오래된 상태라면 release notes가 사용자를 오도할 수 있다."
      }
    ],
    "open_questions": [
      {
        "content": "최종 release approval authority가 누구인지 미정이다."
      },
      {
        "content": "release note에 내부 Wednesday stretch goal을 언급해야 하는지 결정되지 않았다."
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "smoke test를 재실행하고 결과를 공유한다.",
      "due": "Friday 10:00 KST",
      "status": "confirmed",
      "source_certainty": "explicit"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 failure triage note를 작성한다.",
      "due": "Friday 12:00 KST",
      "status": "confirmed",
      "source_certainty": "explicit"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 smoke results를 게시한 뒤 generated tarball path를 확인한다.",
      "due": null,
      "status": "confirmed_without_exact_deadline",
      "source_certainty": "explicit"
    },
    {
      "owner": null,
      "task": "README install steps를 Thursday까지 가능하면 검토한다.",
      "due": "Thursday if possible",
      "status": "unassigned_non_decision",
      "source_certainty": "explicit_owner_missing"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 Friday 10:00 KST smoke test 결과 공유 여부를 확인한다.",
      "Doyun의 Friday 12:00 KST action_items.md failure triage note 작성 여부를 확인한다.",
      "smoke 결과가 게시된 뒤 Hara의 generated tarball path 확인을 추적한다.",
      "README install steps 검토 owner 지정 여부를 확인한다.",
      "최종 release approval authority를 확인한다.",
      "release note에 Wednesday internal stretch goal을 언급할지 결정한다."
    ],
    "do_not_invent": [
      "customer 또는 external partner 이름",
      "budget 정보",
      "security incident",
      "production outage",
      "legal approval requirement",
      "명시되지 않은 owner",
      "명시되지 않은 deadline"
    ]
  },
  "non_invention_rules": [
    "고객명은 언급되지 않았으므로 생성하지 않는다.",
    "예산 정보는 언급되지 않았으므로 생성하지 않는다.",
    "보안 사고는 언급되지 않았으므로 생성하지 않는다.",
    "운영 장애는 언급되지 않았으므로 생성하지 않는다.",
    "법무 승인 요구사항은 언급되지 않았으므로 생성하지 않는다.",
    "owner가 없는 항목은 owner를 추정하지 않는다.",
    "deadline이 없는 항목은 deadline을 추정하지 않는다.",
    "Wednesday는 확정 릴리스 일정이 아니라 내부 stretch goal로만 기록한다."
  ]
}
